import React, { useState } from "react";
import "../styles/login.css";

function Inicio() {
  const [showPassword, setShowPassword] = useState(false);

  return (
    <div className="contenedor">
      <div className="card">

        <h1>inicio</h1>
        <p className="subtitulo">bienvenido a nuestro menú de inicio.</p>

        {/* DOCUMENTO */}
        <label>documento</label>
        <div className="input-group">
          <span className="icon">👤</span>
          <input type="text" placeholder="XXX.XXX.XXX" />
        </div>

        {/* PASSWORD */}
        <label>Password</label>
        <div className="input-group">
          <span className="icon">🔒</span>
          <input
            type={showPassword ? "text" : "password"}
            placeholder="********"
          />
          <span
            className="eye"
            onClick={() => setShowPassword(!showPassword)}
          >
            👁️
          </span>
        </div>

        {/* CODIGO */}
        <label>Código de verificación</label>
        <div className="input-group">
          <span className="icon">💬</span>
          <input type="text" placeholder="•••" />
        </div>

        {/* BOTON */}
        <button className="btn">Crear una cuenta</button>

        {/* FOOTER */}
        <p className="footer">
          © 2026 Financiero. Todos los derechos reservados. Política de seguridad
        </p>

        <p className="registro">
          ¿No tienes cuenta? <span>Regístrate aquí.</span>
        </p>

      </div>
    </div>
  );
}

export default Inicio;
